static float if_avg_path_length(float n) {
    if (n <= 1.0f) return 0.0f;
    if (n <= 2.0f) return 1.0f;
    return 2.0f * (logf(n - 1.0f) + 0.5772156649f) - (2.0f * (n - 1.0f) / n);
}

bool iforest_generated_is_available(void) { return true; }
float iforest_generated_default_threshold(void) { return IF_DEFAULT_THRESHOLD; }
const char *iforest_generated_name(void) { return "iforest_generated_v1"; }

float iforest_generated_predict(const float features[IF_MODEL_NUM_FEATURES]) {
    float x[IF_MODEL_NUM_FEATURES];
    float path_sum = 0.0f;

    for (int i = 0; i < IF_MODEL_NUM_FEATURES; i++) {
        float s = g_scaler_scale[i];
        if (s == 0.0f) s = 1.0f;
        x[i] = (features[i] - g_scaler_mean[i]) / s;
    }

    for (int t = 0; t < IF_NUM_TREES; t++) {
        const if_tree_t *tr = &g_trees[t];
        int idx = 0;
        int depth = 0;

        while (tr->feature[idx] >= 0) {
            int f = tr->feature[idx];
            float thr = tr->threshold[idx];
            idx = (x[f] <= thr) ? tr->left[idx] : tr->right[idx];
            depth++;
            if (idx < 0 || idx >= tr->node_count) {
                break;
            }
        }

        if (idx < 0) idx = 0;
        if (idx >= tr->node_count) idx = tr->node_count - 1;

        float leaf_n = (float)tr->n_node_samples[idx];
        path_sum += (float)depth + if_avg_path_length(leaf_n);
    }

    float avg_path = path_sum / (float)IF_NUM_TREES;
    float score = powf(2.0f, -(avg_path / IF_C_N));
    if (score < 0.0f) score = 0.0f;
    if (score > 1.0f) score = 1.0f;
    return score;
}
